import { useState } from 'react';
import FormContainer from '../components/FormContainer';

const RegisterScreen = ({ onLogin }) => {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');

  return (
    <FormContainer>
      <h1>Registrujte se</h1>
      <form
        onSubmit={(event) => {
          event.preventDefault();
          onLogin(email || 'korisnik@student.ftn.rs', name || 'Novi korisnik');
        }}
      >
        <label>
          Ime
          <input value={name} onChange={(event) => setName(event.target.value)} placeholder="Upisite ime" />
        </label>
        <label>
          Email adresa
          <input value={email} onChange={(event) => setEmail(event.target.value)} placeholder="Upisite email" />
        </label>
        <label>
          Lozinka
          <input type="password" placeholder="Upisite lozinku" />
        </label>
        <button type="submit">Registruj se</button>
      </form>
    </FormContainer>
  );
};

export default RegisterScreen;
